// Native-token transfer. The receiver output carries exactly one native token:
//   8258 <addr> 82 <lovelace> a1 581c<policyId> a1 <assetNameCbor> <tokenAmount>
export const TOKEN_TRANSFER = {
  script: ``,
  signature:
    '3045022100d9afc0a2d579f0d1d61243ad758888af13e8b147c816c2a76f2322b24fe6d4e6022038bf456f6f5d4db47d2c57eadeb9b864f3d8f956691441043e59ec1ddabacdce'.padStart(
      144,
      '0'
    ),
  get scriptWithSignature(): string {
    return this.script + this.signature;
  },
};

// Blind variant of TOKEN_TRANSFER (displayed token amount would reach 1e8, which the SE can't
// render). Body bytes are identical to TOKEN_TRANSFER; display is just `ADA -> SMART -> PRESS`.
